# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch, ConnectionError, TransportError
import os

app = Flask(__name__)

ELASTICSEARCH_HOST = os.environ.get('ELASTICSEARCH_HOST', 'localhost')
ELASTICSEARCH_PORT = int(os.environ.get('ELASTICSEARCH_PORT', 9200))
ELASTICSEARCH_INDEX = os.environ.get('ELASTICSEARCH_INDEX', 'products')

es = None
try:
    es = Elasticsearch(
        [{'host': ELASTICSEARCH_HOST, 'port': ELASTICSEARCH_PORT, 'scheme': 'http'}],
        timeout=30
    )
    if not es.ping():
        raise ValueError("Connection to Elasticsearch failed!")
except Exception:
    es = None

@app.route('/api/search', methods=['GET'])
def search_products():
    if es is None:
        return jsonify({"error": "Search service unavailable. Elasticsearch connection failed at startup."}), 503

    query_string = request.args.get('q', '').strip()

    if not query_string:
        return jsonify({"error": "Query parameter 'q' is required."}), 400

    try:
        search_body = {
            "query": {
                "multi_match": {
                    "query": query_string,
                    "fields": ["name^3", "description", "tags"],
                    "type": "best_fields",
                    "fuzziness": "AUTO"
                }
            },
            "size": 20
        }

        res = es.search(index=ELASTICSEARCH_INDEX, body=search_body)

        products = []
        for hit in res['hits']['hits']:
            products.append(hit['_source'])

        return jsonify(products)

    except ConnectionError:
        return jsonify({"error": "Could not connect to Elasticsearch. Please try again later."}), 503
    except TransportError as e:
        status_code = e.status_code if hasattr(e, 'status_code') else 500
        error_reason = e.info.get('error', {}).get('reason', 'Unknown Elasticsearch error') if hasattr(e, 'info') else 'Unknown error'
        return jsonify({"error": f"Elasticsearch error: {status_code} - {error_reason}"}), status_code
    except Exception:
        return jsonify({"error": "An unexpected error occurred."}), 500

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)